import{c as e,Q as r,j as a,m as s}from"./chunks/framework.BXc4yaFE.js";const u=JSON.parse('{"title":"Model-Harness Fit（MHF）","description":"","frontmatter":{},"headers":[],"relativePath":"resources/research/model-harness-fit.md","filePath":"resources/research/model-harness-fit.md","lastUpdated":1779796674000}'),d={name:"resources/research/model-harness-fit.md"};function o(n,t,l,i,h,c){return r(),a("div",null,[...t[0]||(t[0]=[s('<h1 id="model-harness-fit-mhf" tabindex="-1">Model-Harness Fit（MHF） <a class="header-anchor" href="#model-harness-fit-mhf" aria-label="Permalink to &quot;Model-Harness Fit（MHF）&quot;">​</a></h1><blockquote><p>來源：2026-05-16 深度研究報告（48 篇 scored articles + 本地研究材料交叉驗證）</p></blockquote><p><strong>Harness Model Fit（HMF）</strong> 描述 harness 設計與目標模型能力之間的對齊程度。這是 Harness Engineering 的核心子問題：harness 的每一個元件是否和「當前模型的能力邊界」正確對齊？</p><hr><h2 id="核心等式" tabindex="-1">核心等式 <a class="header-anchor" href="#核心等式" aria-label="Permalink to &quot;核心等式&quot;">​</a></h2><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Harness ⊇ Context ⊇ Prompt</span></span></code></pre></div><p>Harness 是最外層，決定模型的整個執行環境。Context 是模型在單次 session 中能「看到」的內容。Prompt 是具體的指令輸入。<strong>所有 prompt 工程技巧的效益上限，都被 harness 設計所封頂。</strong></p><hr><h2 id="三種-harness-model-失配狀態" tabindex="-1">三種 Harness-Model 失配狀態 <a class="header-anchor" href="#三種-harness-model-失配狀態" aria-label="Permalink to &quot;三種 Harness-Model 失配狀態&quot;">​</a></h2><table tabindex="0"><thead><tr><th>失配類型</th><th>描述</th><th>症狀</th></tr></thead><tbody><tr><td><strong>Over-scaffolding</strong></td><td>Harness 補足已不必要的缺口</td><td>冗餘提示詞、不必要的驗證步驟、token 浪費</td></tr><tr><td><strong>Under-scaffolding</strong></td><td>Harness 沒有覆蓋模型實際能力邊界</td><td>Agent 行為不可預測、錯誤恢復失敗</td></tr><tr><td><strong>Model-drift</strong></td><td>模型升級後 harness 未隨之更新</td><td>舊假設累積成死重，效能低於預期</td></tr></tbody></table><blockquote><p><strong>Anthropic 的長期觀點</strong>：每個 harness 元件都是一項假設——「模型無法自行完成 X，因此 harness 補足它」。模型能力提升時，需要年度 harness audit 系統性移除過時假設。</p></blockquote><hr><h2 id="量化證據" tabindex="-1">量化證據 <a class="header-anchor" href="#量化證據" aria-label="Permalink to &quot;量化證據&quot;">​</a></h2><p>同一模型在不同 harness 中的效能差距 <strong>5.2–40 個百分點</strong>：</p><table tabindex="0"><thead><tr><th>案例</th><th>介入</th><th>效果</th></tr></thead><tbody><tr><td>Can.ac</td><td>Harness 重設計</td><td>6.7% → 68.3%（<strong>10 倍</strong>）</td></tr><tr><td>LangChain</td><td>純 harness 改善</td><td>52.8% → 66.5%（<strong>+13.7pp</strong>，不換模型）</td></tr><tr><td>SWE-agent CLI 重設計</td><td>無模型改變</td><td>~40% 提升</td></tr><tr><td>AgentFlow 同模型不同 harness</td><td>效能差 4 倍</td><td>量化確認</td></tr><tr><td>AgentOpt 最佳/最差模型組合</td><td>相同準確率</td><td>成本差 <strong>13-32 倍</strong></td></tr><tr><td>Terminal-Bench 2.0（ForgeCode vs Crux）</td><td>同 Opus 4.6</td><td>79.8% vs 66.9%（<strong>13pp</strong>）</td></tr></tbody></table><hr><h2 id="六維正式框架" tabindex="-1">六維正式框架 <a class="header-anchor" href="#六維正式框架" aria-label="Permalink to &quot;六維正式框架&quot;">​</a></h2><p><strong>Agent Harness Survey（2026-04-07）</strong> 提出：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>H = (E, T, C, S, L, V)</span></span></code></pre></div><table tabindex="0"><thead><tr><th>維度</th><th>說明</th></tr></thead><tbody><tr><td><strong>E（Execution Loop）</strong></td><td>ReAct / Plan-Execute / Planner+Executor 分離</td></tr><tr><td><strong>T（Tool Integration）</strong></td><td>工具介面設計、lazy loading、授權邊界</td></tr><tr><td><strong>C（Context Management）</strong></td><td>壓縮策略、記憶分層、rot 防止</td></tr><tr><td><strong>S（State Persistence）</strong></td><td>跨 session 記憶、checkpoint、filesystem</td></tr><tr><td><strong>L（Lifecycle Governance）</strong></td><td>hooks、guardrails、safety gates</td></tr><tr><td><strong>V（Evaluation Interfaces）</strong></td><td>驗證迴路、量化指標、regression 測試</td></tr></tbody></table><hr><h2 id="七大架構決策軸" tabindex="-1">七大架構決策軸 <a class="header-anchor" href="#七大架構決策軸" aria-label="Permalink to &quot;七大架構決策軸&quot;">​</a></h2><p>根據 Anatomy of Agent Harness（2026-04-01），任何 harness 設計必須在以下七個軸做出選擇：</p><table tabindex="0"><thead><tr><th>軸</th><th>選項</th><th>建議</th></tr></thead><tbody><tr><td>1. 單 Agent vs 多 Agent</td><td>Single / Multi</td><td>單一 well-harnessed agent 在大多數任務優於多個弱協調的專業 agent</td></tr><tr><td>2. 執行模式</td><td>ReAct / Plan-Execute</td><td>ReAct 適探索性任務；Plan-Execute 適長序列確定性任務</td></tr><tr><td>3. Context 壓縮策略</td><td>Rolling window / Summary / Hierarchical</td><td>雙層方案（Confucius）效果最佳</td></tr><tr><td>4. 工具數量</td><td>單一 / 分割</td><td>超過 10 個工具應分割 sub-agent；lazy loading 減少 95% 平時 token</td></tr><tr><td>5. 驗證機制深度</td><td>規則型 / 視覺 / LLM-as-judge</td><td>三層組合達 2-3× 品質提升</td></tr><tr><td>6. 記憶持久化方式</td><td>Filesystem / Context window / Episodic</td><td>長期 filesystem，短期 context，跨 session episodic notes</td></tr><tr><td>7. 錯誤恢復層次</td><td>Retry / Rollback / Decompose / Escalate</td><td>四層分級，從最廉價到最昂貴</td></tr></tbody></table><hr><h2 id="car-框架" tabindex="-1">CAR 框架 <a class="header-anchor" href="#car-框架" aria-label="Permalink to &quot;CAR 框架&quot;">​</a></h2><p><strong>CAR（2026-04-23）</strong> 將執行層分解為三維度：</p><table tabindex="0"><thead><tr><th>維度</th><th>說明</th><th>範例</th></tr></thead><tbody><tr><td><strong>C（Control）</strong></td><td>執行前編碼的約束</td><td>CLAUDE.md、linter、pre-commit</td></tr><tr><td><strong>A（Agency）</strong></td><td>模型的動作空間與工具介面</td><td>Tool registry、allowed tools</td></tr><tr><td><strong>R（Runtime）</strong></td><td>時間性治理</td><td>hooks、PostToolUse、Stop hooks</td></tr></tbody></table><hr><h2 id="feedforward-vs-feedback-controls" tabindex="-1">Feedforward vs Feedback Controls <a class="header-anchor" href="#feedforward-vs-feedback-controls" aria-label="Permalink to &quot;Feedforward vs Feedback Controls&quot;">​</a></h2><p>根據 Martin Fowler 的分析：</p><h3 id="feedforward-引導型-—-預防問題" tabindex="-1">Feedforward（引導型）— 預防問題 <a class="header-anchor" href="#feedforward-引導型-—-預防問題" aria-label="Permalink to &quot;Feedforward（引導型）— 預防問題&quot;">​</a></h3><ul><li>CLAUDE.md 常駐規則</li><li>ADR（架構決策記錄）</li><li>Structural tests（架構合規測試）</li><li>Conditional rules / globs</li></ul><h3 id="feedback-感知型-—-發現問題" tabindex="-1">Feedback（感知型）— 發現問題 <a class="header-anchor" href="#feedback-感知型-—-發現問題" aria-label="Permalink to &quot;Feedback（感知型）— 發現問題&quot;">​</a></h3><table tabindex="0"><thead><tr><th>機制</th><th>反饋速度</th><th>修正成本</th></tr></thead><tbody><tr><td>PostToolUse hooks</td><td>ms 級</td><td>趨近於零</td></tr><tr><td>Pre-commit linters</td><td>seconds 級</td><td>低</td></tr><tr><td>CI 測試</td><td>minutes 級</td><td>中</td></tr><tr><td>Human review</td><td>hours 級</td><td>高</td></tr></tbody></table><p><strong>關鍵洞見</strong>：Feedback 速度層次決定修正成本。PostToolUse 在 ms 內攔截問題，成本趨近於零；Human review 在數小時後才發現，修正成本倍增。</p><hr><h2 id="tool-format-的-byte-level-重要性" tabindex="-1">Tool Format 的 Byte-Level 重要性 <a class="header-anchor" href="#tool-format-的-byte-level-重要性" aria-label="Permalink to &quot;Tool Format 的 Byte-Level 重要性&quot;">​</a></h2><p>MHF 研究的一個關鍵發現：<strong>工具介面格式是 byte-level 的後訓練習慣</strong>。</p><ul><li>OpenAI 模型訓練時使用 V4A patch 格式</li><li>Claude 模型訓練時使用 string-replace 格式</li><li><strong>跨模型遷移工具格式 → 推理 token 增加 + 錯誤率上升</strong></li></ul><p>這解釋了為什麼 Claude Code 的 <code>apply_patch</code> 工具比同等功能的其他工具更有效——模型和工具是協同訓練的。</p><hr><h2 id="model-升級後的-harness-audit" tabindex="-1">Model 升級後的 Harness Audit <a class="header-anchor" href="#model-升級後的-harness-audit" aria-label="Permalink to &quot;Model 升級後的 Harness Audit&quot;">​</a></h2><p><strong>Anthropic April 23 Postmortem（2026-04-23）</strong> 提供了一個反面教材：</p><p>Claude Code 的品質回歸不是模型退化，而是三項 harness 改動的累積效果：</p><ol><li>推理預算 default 值：<code>high</code> → <code>medium</code>（降低延遲，但智力下降）</li><li>KV cache bug：推理歷史每輪清除，而非每 session 清除</li><li>系統提示字數限制：「≤25 words between tool calls」造成 3% 智力下降</li></ol><p><strong>預防措施</strong>：</p><ul><li>每次 harness 改動都需要回歸測試</li><li>Reasoning effort 改變 = harness 改動 = 需要測試</li><li>System prompt 修改 = harness 改動 = 需要 regression suite</li><li>漸進式 rollout（5% → 25% → 100%）</li></ul><hr><h2 id="年度-harness-audit-清單" tabindex="-1">年度 Harness Audit 清單 <a class="header-anchor" href="#年度-harness-audit-清單" aria-label="Permalink to &quot;年度 Harness Audit 清單&quot;">​</a></h2><p>模型每次升級後應審查：</p><ul><li>[ ] <strong>Context reset 機制</strong>：模型是否已能自行管理 context？（消除 Over-scaffolding）</li><li>[ ] <strong>Retry logic</strong>：模型是否已更可靠，retry 層可以簡化？</li><li>[ ] <strong>Validation prompts</strong>：哪些驗證提示是模型現在原生具備的能力？</li><li>[ ] <strong>Tool descriptions</strong>：措辭是否需要更新以配合新模型的理解方式？</li><li>[ ] <strong>Reasoning effort default</strong>：新模型的預設 effort 是否適合你的工作負載？</li><li>[ ] <strong>Sub-agent boundary</strong>：哪些任務現在可以由單一 agent 完成，不再需要委派？</li></ul><hr><h2 id="延伸閱讀" tabindex="-1">延伸閱讀 <a class="header-anchor" href="#延伸閱讀" aria-label="Permalink to &quot;延伸閱讀&quot;">​</a></h2><ul><li><a href="/cc-workspace-docs/resources/research/harness-engineering/">Harness Engineering 研究全景</a></li><li><a href="/cc-workspace-docs/resources/research/knowledge-map/">跨源知識地圖</a></li><li><a href="/cc-workspace-docs/lectures/lecture-01-foundations/">Lecture 01：Claude Code 與 Harness 基礎</a></li><li><a href="/cc-workspace-docs/lectures/lecture-04-harness-architecture/">Lecture 04：Harness 三層架構</a></li></ul>',55)])])}const p=e(d,[["render",o]]);export{u as __pageData,p as default};
